    46→/// Monitors network performance and tracks request/response metrics
    47→class NetworkMonitor {
    48→  /// Maximum number of requests to keep in history
    49→  static const int _maxHistorySize = 100;
    50→
    51→  /// Queue of recent network requests
    52→  final Queue<NetworkRequestInfo> _requestHistory = Queue<NetworkRequestInfo>();
    53→
    54→  /// Threshold for slow requests in milliseconds
    55→  static const int _slowRequestThresholdMs = 1000;
    56→
    57→  /// Track a network request
    58→  void trackRequest(String endpoint) {
    59→    debugPrint('🌐 Network request to: $endpoint');
    60→  }
    61→
    62→  /// Track a network response
    63→  void trackResponse(String path, int statusCode) {
    64→    debugPrint('✅ Network response from: $path (Status: $statusCode)');
    65→  }
    66→
    67→  /// Track a network error
    68→  void trackError(String path, String errorMessage) {
    69→    debugPrint('❌ Network error for: $path\nError: $errorMessage');
    70→  }
    71→
    72→  /// Track a network request and its response
    73→  void trackRequestAndResponse({
    74→    required String path,
    75→    required Duration duration,
    76→    required int statusCode,
    77→    required int responseSize,
    78→    bool isError = false,
    79→    String? errorMessage,
    80→  }) {
    81→    final request = NetworkRequestInfo(
    82→      path: path,
    83→      duration: duration,
    84→      statusCode: statusCode,
    85→      responseSize: responseSize,
    86→      isError: isError,
    87→      errorMessage: errorMessage,
    88→    );
    89→
    90→    // Add to history
    91→    _requestHistory.add(request);
    92→
    93→    // Trim history if needed
    94→    while (_requestHistory.length > _maxHistorySize) {
    95→      _requestHistory.removeFirst();
    96→    }
    97→
    98→    // Log slow requests
    99→    if (duration.inMilliseconds > _slowRequestThresholdMs) {
   100→      debugPrint(
   101→          '⚠️ Slow network request: ${request.path} took ${duration.inMilliseconds}ms');
   102→    }
   103→
   104→    // Log errors
   105→    if (isError) {
   106→      debugPrint('❌ Network request error: ${request.path} - $errorMessage');
   107→    } else {
   108→      debugPrint(
   109→          '✅ Network request: ${request.path} - ${duration.inMilliseconds}ms');
   110→    }
   111→  }
   112→
   113→  /// Get the request history
   114→  List<NetworkRequestInfo> getRequestHistory() {
   115→    return List.unmodifiable(_requestHistory);
   116→  }
   117→
   118→  /// Get the average request duration for a specific path
   119→  Duration getAverageRequestDuration(String path) {
   120→    final requests = _requestHistory.where((r) => r.path == path).toList();
   121→
   122→    if (requests.isEmpty) {
   123→      return Duration.zero;
   124→    }
   125→
   126→    final totalMs = requests.fold<int>(
   127→      0,
   128→      (sum, request) => sum + request.duration.inMilliseconds,
   129→    );
   130→
   131→    return Duration(milliseconds: totalMs ~/ requests.length);
   132→  }
   133→
   134→  /// Get the error rate for a specific path
   135→  double getErrorRate(String path) {
   136→    final requests = _requestHistory.where((r) => r.path == path).toList();
   137→
   138→    if (requests.isEmpty) {
   139→      return 0.0;
   140→    }
   141→
   142→    final errorCount = requests.where((r) => r.isError).length;
   143→
   144→    return errorCount / requests.length;
   145→  }
