   210→      case DioExceptionType.badResponse:
   211→        final statusCode = e.response?.statusCode;
   212→        final message = e.response?.data['message'] ?? 'Unknown error occurred';
   213→        final errors = e.response?.data['errors'] as Map<String, List<String>>?;
   214→
   215→        switch (statusCode) {
   216→          case 400:
