    64→
    65→  /// Creates a new [SyncStatusNotifier]
    66→  ///
    67→  /// [_syncManager] - The sync manager to monitor
    68→  SyncStatusNotifier(this._syncManager)
    69→      : super(_syncManager.currentStatus) {
    70→    // Start monitoring sync status
    71→    _startMonitoring();
    72→  }
    73→
    74→  /// Start monitoring sync status changes
    75→  void _startMonitoring() {
    76→    // Subscribe to sync status updates
    77→    _subscription = _syncManager.syncStatusStream.listen(
    78→      (status) {
    79→        // Update state when sync status changes
    80→        state = status;
    81→      },
    82→      onError: (error) {
    83→        // Handle errors by setting error state
    84→        state = SyncStatus.error(
    85→          'Sync stream error: $error',
    86→          pendingOperations: state.pendingOperations,
    87→          lastSyncTime: state.lastSyncTime,
    88→        );
    89→      },
    90→    );
    91→  }
    92→
    93→  /// Trigger a manual sync cycle
    94→  ///
    95→  /// This initiates a sync operation regardless of whether there are
    96→  /// pending operations. Use [force] to bypass certain checks.
    97→  ///
    98→  /// Returns the [SyncResult] when sync completes.
    99→  Future<SyncResult> triggerSync({bool force = false}) async {
   100→    try {
   101→      return await _syncManager.startSync(force: force);
   102→    } catch (e) {
   103→      // State will be updated by the stream
   104→      rethrow;
   105→    }
   106→  }
   107→
   108→  /// Stop the current sync cycle
   109→  ///
   110→  /// Gracefully stops the current sync operation.
   111→  /// Returns [true] if sync was stopped, [false] if no sync was in progress.
   112→  Future<bool> stopSync() async {
   113→    return await _syncManager.stopSync();
   114→  }
   115→
   116→  /// Pause automatic sync triggers
   117→  ///
   118→  /// When paused, the sync manager will not automatically trigger sync
   119→  /// when connectivity changes. Manual sync can still be triggered.
   120→  void pauseAutoSync() {
   121→    _syncManager.pauseAutoSync();
   122→  }
   123→
   124→  /// Resume automatic sync triggers
   125→  ///
   126→  /// Re-enables automatic sync when connectivity changes.
   127→  void resumeAutoSync() {
   128→    _syncManager.resumeAutoSync();
   129→  }
   130→
   131→  /// Refresh sync status
   132→  ///
   133→  /// Gets the current sync status from the manager and updates state.
   134→  /// This is useful for ensuring the state is up-to-date after returning
   135→  /// to the screen.
   136→  void refresh() {
   137→    state = _syncManager.currentStatus;
   138→  }
